topics.semanticHtml.sections.whenNativeI:
// Has role, keyboard, and announced state
// Note: <button> is still preferable if styling allows
<div
  role="button"
  tabIndex={0}
  aria-expanded={isOpen}
  aria-haspopup="menu"
  onClick={toggleMenu}
  onKeyDown={(e) => {
    if (e.key === 'Enter' || e.key === ' ') toggleMenu();
  }}
>
  Menu
</div>
